package main

import (
    "crypto/tls"
    "net/http"
    "time"
)

// Compliant: Secure TLS client configuration
func createSecureClient() *http.Client {
    return &http.Client{
        Transport: &http.Transport{
            TLSClientConfig: &tls.Config{
                MinVersion: tls.VersionTLS12, // Minimum TLS 1.2
                // MaxVersion not set = use latest available
                CipherSuites: []uint16{
                    tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                    tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
                    tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305,
                    tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305,
                    tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
                    tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
                },
                CurvePreferences: []tls.CurveID{
                    tls.X25519,
                    tls.CurveP256,
                    tls.CurveP384,
                },
                PreferServerCipherSuites: true,
            },
            TLSHandshakeTimeout: 10 * time.Second,
        },
        Timeout: 30 * time.Second,
    }
}

// Compliant: Modern TLS 1.3 preferred client
func createModernTLSClient() *http.Client {
    return &http.Client{
        Transport: &http.Transport{
            TLSClientConfig: &tls.Config{
                MinVersion: tls.VersionTLS13, // TLS 1.3 only
                // TLS 1.3 automatically uses secure ciphers
            },
        },
    }
}

// Compliant: Secure server configuration
func startSecureServer() {
    server := &http.Server{
        Addr:         ":8443",
        TLSConfig:    getSecureTLSConfig(),
        ReadTimeout:  15 * time.Second,
        WriteTimeout: 15 * time.Second,
        IdleTimeout:  60 * time.Second,
    }

    server.ListenAndServeTLS("cert.pem", "key.pem")
}

func getSecureTLSConfig() *tls.Config {
    return &tls.Config{
        MinVersion: tls.VersionTLS12,
        CipherSuites: []uint16{
            // AEAD ciphers with forward secrecy
            tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
            tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
            tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305,
            tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305,
            tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
            tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
        },
        CurvePreferences: []tls.CurveID{
            tls.X25519, // Most secure curve
            tls.CurveP256,
        },
        PreferServerCipherSuites: true,
        NextProtos:              []string{"h2", "http/1.1"},
    }
}

// Compliant: TLS configuration factory with security levels
type TLSSecurityLevel int

const (
    SecurityLevelModern TLSSecurityLevel = iota
    SecurityLevelIntermediate
    SecurityLevelCompatible
)

func CreateTLSConfig(level TLSSecurityLevel) *tls.Config {
    switch level {
    case SecurityLevelModern:
        return &tls.Config{
            MinVersion: tls.VersionTLS13,
            // TLS 1.3 handles cipher selection automatically
            CurvePreferences: []tls.CurveID{
                tls.X25519,
            },
        }
    case SecurityLevelIntermediate:
        return &tls.Config{
            MinVersion: tls.VersionTLS12,
            CipherSuites: []uint16{
                tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
                tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305,
                tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305,
                tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
                tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
            },
            CurvePreferences: []tls.CurveID{
                tls.X25519,
                tls.CurveP256,
                tls.CurveP384,
            },
            PreferServerCipherSuites: true,
        }
    case SecurityLevelCompatible:
        return &tls.Config{
            MinVersion: tls.VersionTLS12, // Still no lower than 1.2
            CipherSuites: []uint16{
                // Include some additional ciphers for compatibility
                tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
                tls.TLS_RSA_WITH_AES_256_GCM_SHA384,
                tls.TLS_RSA_WITH_AES_128_GCM_SHA256,
            },
            PreferServerCipherSuites: true,
        }
    default:
        // Default to intermediate security
        return CreateTLSConfig(SecurityLevelIntermediate)
    }
}

// Compliant: HTTP client with security validation
func createValidatingClient() *http.Client {
    return &http.Client{
        Transport: &http.Transport{
            TLSClientConfig: &tls.Config{
                MinVersion: tls.VersionTLS12,
                CipherSuites: []uint16{
                    tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                    tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
                },
                // Certificate validation is enabled by default
                InsecureSkipVerify: false,
                VerifyConnection: func(cs tls.ConnectionState) error {
                    // Additional connection validation
                    if cs.Version < tls.VersionTLS12 {
                        return fmt.Errorf("TLS version %x is too old", cs.Version)
                    }
                    return nil
                },
            },
        },
    }
}

// Compliant: Utility for checking TLS configuration security
func ValidateTLSConfig(config *tls.Config) []string {
    var warnings []string

    if config.MinVersion < tls.VersionTLS12 {
        warnings = append(warnings, "TLS version below 1.2 is insecure")
    }

    // Check for weak cipher suites
    weakCiphers := map[uint16]string{
        tls.TLS_RSA_WITH_RC4_128_SHA:       "RC4 is broken",
        tls.TLS_RSA_WITH_3DES_EDE_CBC_SHA:  "3DES is weak",
        tls.TLS_ECDHE_RSA_WITH_RC4_128_SHA: "RC4 is broken",
    }

    for _, cipher := range config.CipherSuites {
        if reason, isWeak := weakCiphers[cipher]; isWeak {
            warnings = append(warnings, fmt.Sprintf("Weak cipher suite detected: %s", reason))
        }
    }

    return warnings
}
